using System;
using System.Drawing;
using System.Drawing.Drawing2D;
using System.Drawing.Imaging;
using System.IO;
using System.Runtime.InteropServices;
// Image is pre-boosted for vibrant colours — no runtime ColorMatrix needed

namespace AngryAudio
{
    public static class Mascot
    {
        [DllImport("user32.dll", CharSet = CharSet.Auto)]
        private static extern bool DestroyIcon(IntPtr handle);

        private static Bitmap _cached;

        /// <summary>Creates a 32x32 mascot Icon with proper GDI handle cleanup.</summary>
        public static Icon CreateIcon() {
            using (var bmp = new Bitmap(32, 32, System.Drawing.Imaging.PixelFormat.Format32bppArgb))
            using (var g = Graphics.FromImage(bmp)) {
                try {
                    DrawMascotHead(g, 0, 0, 32);
                } catch { }
                // Build proper ICO with embedded PNG for true alpha transparency
                using (var pngStream = new System.IO.MemoryStream()) {
                    bmp.Save(pngStream, System.Drawing.Imaging.ImageFormat.Png);
                    byte[] pngBytes = pngStream.ToArray();
                    using (var icoStream = new System.IO.MemoryStream()) {
                        icoStream.Write(new byte[] { 0, 0, 1, 0, 1, 0 }, 0, 6);
                        icoStream.WriteByte(32); icoStream.WriteByte(32);
                        icoStream.WriteByte(0); icoStream.WriteByte(0);
                        icoStream.Write(new byte[] { 1, 0, 32, 0 }, 0, 4);
                        icoStream.Write(BitConverter.GetBytes(pngBytes.Length), 0, 4);
                        icoStream.Write(BitConverter.GetBytes(22), 0, 4);
                        icoStream.Write(pngBytes, 0, pngBytes.Length);
                        icoStream.Seek(0, System.IO.SeekOrigin.Begin);
                        return new Icon(icoStream);
                    }
                }
            }
        }

        public static Bitmap GetImage()
        {
            if (_cached != null && _cached.Width > 0) return _cached;
            try
            {
                string exeDir = Path.GetDirectoryName(System.Reflection.Assembly.GetExecutingAssembly().Location);
                string pngPath = Path.Combine(exeDir, "Angry Audio Mascot.png");
                if (File.Exists(pngPath))
                {
                    _cached = new Bitmap(pngPath);
                    return _cached;
                }
                byte[] data = Convert.FromBase64String(MASCOT_B64);
                using (var ms = new MemoryStream(data))
                    _cached = new Bitmap(ms);
                return _cached;
            }
            catch
            {
                _cached = new Bitmap(1, 1);
                return _cached;
            }
        }

        // Color matrix — original colors, no manipulation
        private static ImageAttributes GetBoostAttributes(float opacity = 1f)
        {
            var cm = new ColorMatrix(new float[][] {
                new float[] { 1, 0, 0, 0, 0 },
                new float[] { 0, 1, 0, 0, 0 },
                new float[] { 0, 0, 1, 0, 0 },
                new float[] { 0, 0, 0, opacity, 0 },
                new float[] { 0, 0, 0, 0, 1 }
            });
            var ia = new ImageAttributes();
            ia.SetColorMatrix(cm, ColorMatrixFlag.Default, ColorAdjustType.Bitmap);
            return ia;
        }

        public static void DrawMascot(Graphics g, float x, float y, float size)
        {
            try
            {
                var img = GetImage();
                if (img.Width <= 1) return;
                g.InterpolationMode = InterpolationMode.HighQualityBicubic;
                g.SmoothingMode = SmoothingMode.HighQuality;
                g.PixelOffsetMode = System.Drawing.Drawing2D.PixelOffsetMode.HighQuality;
                using (var ia = GetBoostAttributes())
                    g.DrawImage(img, new Rectangle((int)x, (int)y, (int)size, (int)size),
                        0, 0, img.Width, img.Height, GraphicsUnit.Pixel, ia);
            }
            catch { }
        }

        /// <summary>Draws just the head/headphones region of the mascot, cropped tight on the face for tray icon use.</summary>
        public static void DrawMascotHead(Graphics g, float x, float y, float size)
        {
            try
            {
                var img = GetImage();
                if (img.Width <= 1) return;
                g.InterpolationMode = InterpolationMode.HighQualityBicubic;
                g.SmoothingMode = SmoothingMode.HighQuality;
                g.PixelOffsetMode = System.Drawing.Drawing2D.PixelOffsetMode.HighQuality;
                // Full cat. No crop. No peek. Just draw it.
                using (var ia = GetIconAttributes())
                    g.DrawImage(img, new Rectangle((int)x, (int)y, (int)size, (int)size),
                        0, 0, img.Width, img.Height, GraphicsUnit.Pixel, ia);
            }
            catch { }
        }

        /// <summary>Icon rendering — original colors, no manipulation.</summary>
        private static ImageAttributes GetIconAttributes()
        {
            var cm = new ColorMatrix(new float[][] {
                new float[] { 1, 0, 0, 0, 0 },
                new float[] { 0, 1, 0, 0, 0 },
                new float[] { 0, 0, 1, 0, 0 },
                new float[] { 0, 0, 0, 1, 0 },
                new float[] { 0, 0, 0, 0, 1 }
            });
            var ia = new ImageAttributes();
            ia.SetColorMatrix(cm, ColorMatrixFlag.Default, ColorAdjustType.Bitmap);
            return ia;
        }

        public static void DrawMascotWithOpacity(Graphics g, float x, float y, float size, float opacity)
        {
            try
            {
                var img = GetImage();
                if (img.Width <= 1) return;
                g.InterpolationMode = InterpolationMode.HighQualityBicubic;
                using (var ia = GetBoostAttributes(opacity))
                    g.DrawImage(img, new Rectangle((int)x, (int)y, (int)size, (int)size), 0, 0, img.Width, img.Height, GraphicsUnit.Pixel, ia);
            }
            catch { }
        }

        private const string MASCOT_B64 = "";
    }
}
